                <CaptionCard
                  key={platform}
                  platform={platform}
                  caption={text}
                  onUpdate={(newText) => handleCaptionUpdate(platform, newText)}
                  onRefine={(instruction) => handleRefine(platform, instruction)}
                  onRewrite={() => handleRewrite(platform)}
                  isProcessing={!!processingPlatforms[platform]}
                />
              ))}
            </div>
          </motion.div>
        )}

      </div>
    </Layout>
  );
}

