  const onDrop = useCallback(async (acceptedFiles: File[]) => {
    const selected = acceptedFiles[0];
    if (selected) {
      setFile(selected);
      setPreview(URL.createObjectURL(selected));
      setBase64Data(null);
      setCompressedBytes(null);
      try {
        const result = await compressImage(selected);
        setBase64Data(result.base64);
        setImageMediaType(result.mediaType);
        setCompressedBytes(result.compressedBytes);
      } catch (e) {
        toast({ variant: "destructive", title: "Error", description: "Failed to process image." });
      }
